mapper.select:
/** CmmtHldyDao.selectList */
select

from
	cmmt_hldy
where
	substring(ymd, 1, 4) = #{year}

		and ymd_nm = #{ymdNm}

mapper.insert:
/** CmmthldyDao.insert */
insert into cmmt_hldy (
	 ymd
	,ymd_nm
	,user_dsgn
) values (
	 #{ymd}
	,#{ymdNm}
	,#{userDsgn}
)

mapper.select:
/** CmmtHldyDao.select */
select

	from
		cmmt_hldy
	where
		ymd = #{ymd}

mapper.update:
/** CmmtHldyDao.update */
update cmmt_hldy set
	 ymd 		= #{ymd}
	,ymd_nm 	= #{ymdNm}
	,user_dsgn  = #{userDsgn}
where
	ymd = #{ymd}

mapper.insert:
/** CmmtHldyDao.delete */
delete from
	cmmt_hldy
where
	ymd = #{ymd}
